function mergeUsers(...arrays) {
   
    const mergedArray = [...new Set([].concat(...arrays))];
    
    const mergeDate = new Date().toISOString();

    return {
        users: mergedArray,
        count: mergedArray.length, 
        mergeDate
    };
}

const users1 = ['user1', 'user2'];
const users2 = ['user2', 'user3', 'user4']; 
const users3 = ['user5'];

const result = mergeUsers(users1, users2, users3);
console.log(result);
